await viewportCapability.set({ width: 390, height: 844 });
var mobileResults = [];
for (const path of ["/", "/works", "/blog", "/links", "/tools"]) {
  await tab.goto(`http://127.0.0.1:4321${path}`);
  await tab.playwright.waitForLoadState({ state: "load", timeoutMs: 10000 });
  const data = await tab.playwright.evaluate(() => {
    const isVisible = (el) => {
      const r = el.getBoundingClientRect();
      const style = getComputedStyle(el);
      return r.width > 0 && r.height > 0 && style.visibility !== "hidden" && style.display !== "none";
    };
    const visible = (selector) => [...document.querySelectorAll(selector)].filter(isVisible);
    const headerRect = document.querySelector("header")?.getBoundingClientRect();
    const menuButton = document.querySelector("#mobile-menu-button");
    return {
      title: document.title,
      h1: visible("h1").map((h) => h.textContent.trim()),
      visibleNavLinks: visible("nav a").map((a) => a.textContent.trim()).filter(Boolean),
      visibleButtons: visible("button").slice(0, 8).map((b) => ({ text: b.textContent.trim().replace(/\s+/g, " "), aria: b.getAttribute("aria-label"), expanded: b.getAttribute("aria-expanded") })),
      firstFoldText: [...document.body.querySelectorAll("h1,h2,p,a,button,label,input")]
        .filter((el) => isVisible(el) && el.getBoundingClientRect().top < window.innerHeight)
        .map((el) => el.textContent.trim().replace(/\s+/g, " "))
        .filter(Boolean)
        .slice(0, 24),
      overflowX: document.documentElement.scrollWidth > document.documentElement.clientWidth,
      headerHeight: headerRect ? Math.round(headerRect.height) : null,
      menuButton: menuButton ? { aria: menuButton.getAttribute("aria-label"), expanded: menuButton.getAttribute("aria-expanded") } : null,
      viewport: { width: window.innerWidth, height: window.innerHeight },
    };
  });
  mobileResults.push({ path, data });
}
await viewportCapability.reset();
nodeRepl.write(JSON.stringify(mobileResults, null, 2));

