		id?: string | number | null;
		method?: string;
		params?: Record<string, unknown>;
		jsonrpc?: string;
	};

	try {
		payload = await request.json();
	} catch {
		return jsonResponse(
			request,
			{
				jsonrpc: "2.0",
				id: null,
				error: {
					code: -32700,
					message: "Parse error",
				},
			},
			{ status: 400 },
		);
	}

	const id = payload.id ?? null;

	if (payload.method === "initialize") {
		return jsonResponse(request, {
			jsonrpc: "2.0",
