			);
		}

		if (pathname === "/llms-full.txt") {
			return textResponse(request, LLMS_FULL_TEXT, "text/plain; charset=utf-8");
		}

		if (pathname === "/auth.md") {
			return textResponse(request, AUTH_MD, "text/markdown; charset=utf-8");
